const imagePrompt = [
  `Create a high-end vertical social image for ${input.brandName}.`,
  `Topic: ${input.selectedTopic}.`,
  `Style: modern, clean, editorial, client-ready, natural light, realistic, no watermark, no logo, no text overlay.`,
  `The image should feel trustworthy and polished for Instagram and Facebook.`
].join(' ');

const videoPrompt = [
  `Create a short vertical social video for ${input.brandName}.`,
  `Topic: ${input.selectedTopic}.`,
  `Recommended concept: ${input.recommended_video_idea || input.video_ideas?.[0] || 'create a practical, helpful short-form video'}.`,
  `Style: polished, natural, platform-native, no watermark, no logo, no text overlay, clear pacing, suitable for TikTok.`,
  `Keep it concise, engaging, and easy to approve.`
].join(' ');

const instagramImageObjectPath = `${safeSlug}/${runKey}-instagram.png`;
const tiktokVideoObjectPath = `${safeSlug}/${runKey}-tiktok.mp4`;

return [{ json: { ...input, assetBucket, assetRunKey: runKey, safeSlug, instagramImagePrompt: imagePrompt, tiktokVideoPrompt: videoPrompt, instagramImageObjectPath, tiktokVideoObjectPath, imageUploadMimeType: 'image/png', videoUploadMimeType: 'video/mp4', videoPollAttempt: 0 } }];

