const base64 = input?.data?.[0]?.b64_json || input?.data?.[0]?.base64 || input?.data?.[0]?.image_base64;

if (!base64) {
  return [{ json: { ...input, imagePrepareError: 'OpenAI image generation did not return base64 image data.' } }];
}

