  Buffer.from(base64, 'base64'),
  'instagram-image.png',
  'image/png'
);

return [{ json: { ...input }, binary: { data: binary } }];

const input = $input.first().json;
const videoPollAttempt = Number(input.videoPollAttempt || 0) + 1;
return [{ json: { ...input, videoPollAttempt } }];

const getNodeJson = (name) => {
  try {
    return $(name).first().json;
  } catch (error) {
    return {};
  }
};

const brief = getNodeJson('Asset Brief Builder');
const imageUpload = getNodeJson('Upload Instagram Image');
const videoStatus = getNodeJson('Get TikTok Video Status');
const videoDownload = getNodeJson('Download TikTok Video');
const videoUpload = getNodeJson('Upload TikTok Video');
const fallback = $input.first().json;

const supabaseUrl = String($env.SUPABASE_URL || '').replace(/\/$/, '');
const imageReady = Boolean(brief.instagramImageObjectPath && !imageUpload.error && !brief.imagePrepareError);
const videoReady = Boolean(brief.tiktokVideoObjectPath && ['completed', 'succeeded'].includes(videoStatus.status) && !videoDownload.error && !videoUpload.error);

const instagramImageUrl = imageReady
  ? `${supabaseUrl}/storage/v1/object/public/${brief.assetBucket}/${brief.instagramImageObjectPath}`
  : (brief.instagramImageUrl || fallback.instagramImageUrl || '');
const tiktokVideoUrl = videoReady
  ? `${supabaseUrl}/storage/v1/object/public/${brief.assetBucket}/${brief.tiktokVideoObjectPath}`
  : (brief.tiktokVideoUrl || fallback.tiktokVideoUrl || '');

return [{
  json: {
    ...fallback,
    ...brief,
    instagramImageUrl,
    tiktokVideoUrl,
    assetStatus: imageReady && videoReady ? 'ready' : (imageReady || videoReady ? 'partial' : 'failed'),
    assetGeneratedAt: new Date().toISOString(),
    imageGenerationReady: imageReady,
    videoGenerationReady: videoReady,
    videoJobStatus: videoStatus.status || 'unknown'
  }
}];

const fallback = $input.first().json;
let brief = {};
try {
  brief = $('Asset Brief Builder').first().json;
} catch (error) {
  brief = {};
}
return [{ json: { ...fallback, ...brief, publishPlatform: 'TikTok', publishSucceeded: false, publishErrorText: 'TikTok video generation did not complete in time.' } }];
